#include<iostream>#include<algorithm>#include<vector>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n ;        cin>>n;        vector<pair<ll,ll>>a,b,c;        for(int i=0;i<n;i++){            ll x;             cin>>x;             a.push_back({x,i});        }        for(int i=0;i<n;i++){           ll x;           cin>>x;           b.push_back({x,i});        }        for(int i=0;i<n;i++){            ll x;           cin>>x;           c.push_back({x,i});        }         sort(a.rbegin(),a.rend());        sort(b.rbegin(),b.rend());        sort(c.rbegin(),c.rend());        ll maxi=0;        for(int i=0;i<3;i++){            for(int j=0;j<3;j++){                for(int k=0;k<3;k++){                    if ((a[i].second == b[j].second) or (b[j].second == c[k].second) or (c[k].second == a[i].second))						{continue;}                    maxi= max(maxi,(a[i].first + b[j].first + c[k].first));                }            }        }        cout<<maxi<<"\n";    }}